#!/usr/bin/env python3
# ============================================================
# Detect mixed infections using TSV input
#
# Usage:
#     python3 mixInfection.py <biosample ID>
#
# Input (generated by snpMatrix.py):
#     mixInfection/<biosample ID>/<biosample ID>.tsv
#
# Output:
#     mixInfection/<biosample ID>/<biosample ID>_mixinfection_summary.csv
#
# Masks SNPs falling inside intervals defined in:
#     database/omsCatalog/tbdr.bed
# ============================================================

import sys
import csv
import os
from pathlib import Path

# ============================================================
# PROJECT STRUCTURE
# ============================================================
PROJECT_DIR = Path(
    os.path.abspath(os.path.join(os.path.dirname(__file__), ".."))
)

TSV_ROOT = PROJECT_DIR / "mixInfection"
BED_FILE = PROJECT_DIR / "database" / "omsCatalog" / "tbdr.bed"

MIX_THRESHOLD = 0.35   # default threshold

# ============================================================
# Load BED regions (resistance positions to mask)
# ============================================================
def load_bed_regions(bed_path):
    regions = []
    if not bed_path.exists():
        raise FileNotFoundError(f"BED file not found: {bed_path}")

    with open(bed_path) as fh:
        for line in fh:
            if not line.strip():
                continue
            chrom, start, end = line.strip().split("\t")
            regions.append((chrom, int(start), int(end)))
    return regions


# ============================================================
# Check if SNP must be masked (OMS catalog is 1-based start inclusive, end exclusive)
# ============================================================
def is_masked(chrom, pos1, regions):
    for (r_chrom, start, end) in regions:
        if chrom == r_chrom and start <= pos1 < end:
            return True
    return False


# ============================================================
# Process TSV for one biosample
# ============================================================
def analyze_tsv(tsv_path, regions, mix_thr=MIX_THRESHOLD):

    if not tsv_path.exists():
        print(f"[ERROR] TSV not found: {tsv_path}")
        return 0, 0, 0.0, "NA"

    n_total = 0
    n_het = 0

    with open(tsv_path) as fh:
        reader = csv.DictReader(fh, delimiter="\t")

        for row in reader:
            chrom = row["chrom"]
            pos = int(row["pos"])
            gt_raw = row["gt"]

            gt = gt_raw.replace("|", "/")

            if is_masked(chrom, pos, regions):
                continue

            n_total += 1

            if "/" in gt:
                a1, a2 = gt.split("/")

                if a1 == "." or a2 == ".":
                    continue

                if a1 != a2:
                    n_het += 1

    proportion = (n_het / n_total) if n_total > 0 else 0.0
    status = "MIXED" if proportion >= mix_thr else "NOT MIXED"

    return n_total, n_het, proportion, status


# ============================================================
def main():

    if len(sys.argv) != 2:
        print("Usage: python3 mixInfection.py <biosample>")
        sys.exit(1)

    biosample = sys.argv[1]

    # ================= Locate input/output =================
    sample_dir = TSV_ROOT / biosample
    tsv_path = sample_dir / f"{biosample}.tsv"
    out_csv  = sample_dir / f"{biosample}_mixinfection_summary.csv"

    # ================= SKIP IF SUMMARY EXISTS =================
    if out_csv.exists():
        print(f"[SKIP] MixInfection summary already exists: {out_csv}")
        return

    print("[RUN] MixInfection for a single biosample")
    print(f"[IN]  biosample: {biosample}")
    print(f"[IN]  TSV:       {tsv_path}")
    print(f"[BED] regions:   {BED_FILE}")
    print("---------------------------------------------")

    # ================= Load BED =================
    regions = load_bed_regions(BED_FILE)

    if not tsv_path.exists():
        print(f"[ERROR] Input TSV not found: {tsv_path}")
        sys.exit(1)

    sample_dir.mkdir(parents=True, exist_ok=True)

    # ================= Analysis =================
    n_total, n_het, proportion, status = analyze_tsv(
        tsv_path, regions, MIX_THRESHOLD
    )

    # ================= Write output =================
    with open(out_csv, "w", newline="") as fh:
        writer = csv.writer(fh)
        writer.writerow([
            "biosample", "filename", "total_snps",
            "heterozygous_snps", "proportion", "status"
        ])
        writer.writerow([
            biosample,
            tsv_path.name,
            n_total,
            n_het,
            f"{proportion:.4f}",
            status
        ])

    print(f"[OK] {biosample}: total={n_total} het={n_het} prop={proportion:.3f} → {status}")
    print(f"[OUT] {out_csv}")
    print("---------------------------------------------")
    print("[DONE] MixInfection completed successfully.")


# ============================================================
if __name__ == "__main__":
    main()

